import React, { useState, useMemo } from "react";
import { useData } from "../lib/DataContext";
import { Plus, X, Search, Filter } from "lucide-react";
import { format } from "date-fns";

const STATUS_OPTIONS  = ["Pendiente", "En Progreso", "Completado", "Cancelado"];
const PRIORITY_OPTIONS = ["Alta", "Media", "Baja"];

function statusBadge(s) {
  const map = { "Completado": "badge-success", "En Progreso": "badge-info", "Pendiente": "badge-warn", "Cancelado": "badge-danger" };
  return <span className={`badge ${map[s] || "badge-neutral"}`}>{s}</span>;
}
function priorityBadge(p) {
  const map = { Alta: "badge-danger", Media: "badge-warn", Baja: "badge-neutral" };
  return <span className={`badge ${map[p] || "badge-neutral"}`}>{p}</span>;
}

function WorkOrderModal({ onClose, onSave, mechanics, equipment }) {
  const [form, setForm] = useState({
    equipmentId: "", equipmentName: "", title: "", status: "Pendiente",
    priority: "Media", mechanicId: "", mechanicName: "", notes: ""
  });

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleEq = (id) => {
    const eq = equipment.find(e => e.id === id);
    set("equipmentId", id);
    set("equipmentName", eq?.name || "");
  };
  const handleMech = (id) => {
    const m = mechanics.find(m => m.id === id);
    set("mechanicId", id);
    set("mechanicName", m?.name || "");
  };
  const handleSave = () => {
    if (!form.equipmentId || !form.title || !form.mechanicId) {
      alert("Por favor completa: equipo, título y mecánico.");
      return;
    }
    onSave(form);
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title">Nueva Orden de Trabajo</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          <div className="form-grid">
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Equipo *</label>
              <select className="form-input" value={form.equipmentId} onChange={e => handleEq(e.target.value)}>
                <option value="">Seleccionar equipo…</option>
                {equipment.map(eq => (
                  <option key={eq.id} value={eq.id}>{eq.name}</option>
                ))}
              </select>
            </div>
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Descripción del trabajo *</label>
              <input className="form-input" value={form.title} onChange={e => set("title", e.target.value)} placeholder="Ej: Cambio de aceite y filtros" />
            </div>
            <div className="form-group">
              <label className="form-label">Prioridad</label>
              <select className="form-input" value={form.priority} onChange={e => set("priority", e.target.value)}>
                {PRIORITY_OPTIONS.map(p => <option key={p}>{p}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Estado</label>
              <select className="form-input" value={form.status} onChange={e => set("status", e.target.value)}>
                {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Mecánico asignado *</label>
              <select className="form-input" value={form.mechanicId} onChange={e => handleMech(e.target.value)}>
                <option value="">Seleccionar mecánico…</option>
                {mechanics.filter(m => m.active === "true").map(m => (
                  <option key={m.id} value={m.id}>{m.name} — {m.role}</option>
                ))}
              </select>
            </div>
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Notas adicionales</label>
              <textarea className="form-input" rows={3} value={form.notes} onChange={e => set("notes", e.target.value)} placeholder="Observaciones…" />
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancelar</button>
          <button className="btn btn-primary" onClick={handleSave}>Crear Orden</button>
        </div>
      </div>
    </div>
  );
}

export default function WorkOrders() {
  const { workOrders, mechanics, equipment, addWorkOrder, updateWorkOrder, loading } = useData();
  const [showModal, setShowModal] = useState(false);
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("Todos");
  const [filterPriority, setFilterPriority] = useState("Todos");

  const filtered = useMemo(() => {
    return workOrders
      .filter(wo => {
        const q = search.toLowerCase();
        const matchQ = !q || wo.title?.toLowerCase().includes(q) || wo.equipmentName?.toLowerCase().includes(q) || wo.mechanicName?.toLowerCase().includes(q) || wo.id?.toLowerCase().includes(q);
        const matchS = filterStatus === "Todos" || wo.status === filterStatus;
        const matchP = filterPriority === "Todos" || wo.priority === filterPriority;
        return matchQ && matchS && matchP;
      })
      .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  }, [workOrders, search, filterStatus, filterPriority]);

  const handleSave = async (form) => {
    await addWorkOrder(form);
    setShowModal(false);
  };

  const toggleStatus = async (wo) => {
    const next = { "Pendiente": "En Progreso", "En Progreso": "Completado", "Completado": "Pendiente" };
    await updateWorkOrder({ ...wo, status: next[wo.status] || wo.status });
  };

  if (loading) return <div className="empty-state"><p>Cargando…</p></div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Órdenes de Trabajo</h1>
          <p className="page-subtitle">{filtered.length} órdenes encontradas</p>
        </div>
        <button className="btn btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={16} /> Nueva Orden
        </button>
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>
        <div style={{ position: "relative", flex: 1, minWidth: 200 }}>
          <Search size={14} style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: "var(--text3)" }} />
          <input className="form-input" style={{ paddingLeft: 32 }} placeholder="Buscar órdenes…" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <select className="form-input" style={{ width: "auto" }} value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
          <option value="Todos">Todos los estados</option>
          {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
        </select>
        <select className="form-input" style={{ width: "auto" }} value={filterPriority} onChange={e => setFilterPriority(e.target.value)}>
          <option value="Todos">Toda prioridad</option>
          {PRIORITY_OPTIONS.map(p => <option key={p}>{p}</option>)}
        </select>
      </div>

      {/* Table */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Equipo</th>
                <th>Trabajo</th>
                <th>Mecánico</th>
                <th>Prioridad</th>
                <th>Estado</th>
                <th>Creado</th>
                <th>Acción</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 && (
                <tr><td colSpan={8} style={{ textAlign: "center", padding: 40, color: "var(--text3)" }}>Sin resultados</td></tr>
              )}
              {filtered.map(wo => (
                <tr key={wo.id}>
                  <td><span className="text-mono" style={{ fontSize: 11, color: "var(--text3)" }}>{wo.id}</span></td>
                  <td style={{ fontWeight: 500 }}>{wo.equipmentName}</td>
                  <td style={{ color: "var(--text2)", maxWidth: 200 }}>{wo.title}</td>
                  <td>{wo.mechanicName}</td>
                  <td>{priorityBadge(wo.priority)}</td>
                  <td>{statusBadge(wo.status)}</td>
                  <td><span style={{ fontSize: 12, fontFamily: "var(--font-mono)", color: "var(--text3)" }}>{wo.createdAt?.split(" ")[0]}</span></td>
                  <td>
                    {wo.status !== "Completado" && wo.status !== "Cancelado" && (
                      <button className="btn btn-ghost btn-sm" onClick={() => toggleStatus(wo)}>
                        Avanzar →
                      </button>
                    )}
                    {wo.status === "Completado" && (
                      <span style={{ color: "var(--success)", fontSize: 12 }}>✓ Listo</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <WorkOrderModal
          onClose={() => setShowModal(false)}
          onSave={handleSave}
          mechanics={mechanics}
          equipment={equipment}
        />
      )}
    </div>
  );
}
